    fun `generateMnemonic`(): kotlin.String
    
    fun `getActivity`(): List<ActivityEventFfi>
    
    fun `getBtcPrice`(`currency`: kotlin.String): kotlin.Double?
    
    fun `getBtcPriceUsd`(): kotlin.Double?
    
    fun `getCachedActivity`(): List<ActivityEventFfi>
    
    fun `getContacts`(): List<ContactFfi>
    
    fun `getFeePercent`(): kotlin.Double
    
    fun `getMnemonic`(): kotlin.String
    
    fun `getRpcUrl`(): kotlin.String
    
    fun `getState`(): WalletStateInfo
    
    fun `getTransferRecipient`(`txHash`: kotlin.String): kotlin.String?
    
    fun `handleCompleteOnboarding`(`mnemonic`: kotlin.String)
    
    fun `handleFund`(`amountSats`: kotlin.String): kotlin.String
    
    fun `handleLock`()
    
    fun `handleRagequit`(`recipient`: kotlin.String): kotlin.String
    
    fun `handleRefreshBalance`()
    
    fun `handleRollover`(): kotlin.String
    
    fun `handleSend`(`amountSats`: kotlin.String, `recipient`: kotlin.String): kotlin.String
    
    fun `handleStartSeedBackup`(`mnemonic`: kotlin.String): SeedBackupStateFfi
    
    fun `handleTransfer`(`amountSats`: kotlin.String, `recipient`: kotlin.String): kotlin.String
    
    fun `handleUnlockBiometric`()
    
    fun `handleVerifySeedWord`(`promptIndex`: kotlin.UInt, `answer`: kotlin.String): kotlin.Boolean
    
    fun `handleWithdraw`(`amountSats`: kotlin.String, `recipient`: kotlin.String): kotlin.String
    
    fun `payLightning`(`bolt11`: kotlin.String): kotlin.String
    
    fun `receiveLightningWait`(`swapId`: kotlin.String)
    
    fun `registerPaymentCallback`(`callback`: PaymentNotificationCallback)
    
    fun `saveContact`(`contact`: ContactFfi): kotlin.String
    
    fun `swapBtcToWbtc`(`amountSats`: kotlin.ULong, `exactIn`: kotlin.Boolean): SwapQuoteFfi
    
    fun `swapExecute`(`swapId`: kotlin.String)
    
    fun `swapLimits`(`direction`: kotlin.String): SwapLimitsFfi
    
    fun `swapList`(): List<SwapSummaryFfi>
    
    fun `swapLnToWbtc`(`amountSats`: kotlin.ULong, `exactIn`: kotlin.Boolean): SwapQuoteFfi
    
    fun `swapStatus`(`swapId`: kotlin.String): SwapStatusFfi
    
    fun `swapWbtcToBtc`(`amountSats`: kotlin.ULong, `btcAddress`: kotlin.String, `exactIn`: kotlin.Boolean): SwapQuoteFfi
    
    fun `updateContactLastUsed`(`contactId`: kotlin.String)
    
    fun `updateRpcUrl`(`url`: kotlin.String)
    
    fun `validateMnemonic`(`phrase`: kotlin.String)
    
    companion object
}

open class OubliWallet: Disposable, AutoCloseable, OubliWalletInterface
{

    constructor(pointer: Pointer) {
        this.pointer = pointer
        this.cleanable = UniffiLib.CLEANER.register(this, UniffiCleanAction(pointer))
    }

    /**
     * This constructor can be used to instantiate a fake object. Only used for tests. Any
     * attempt to actually use an object constructed this way will fail as there is no
     * connected Rust object.
     */
    @Suppress("UNUSED_PARAMETER")
    constructor(noPointer: NoPointer) {
        this.pointer = null
        this.cleanable = UniffiLib.CLEANER.register(this, UniffiCleanAction(pointer))
    }
    constructor(`storage`: PlatformStorageCallback, `rpcUrl`: kotlin.String?, `paymasterApiKey`: kotlin.String?) :
        this(
    uniffiRustCallWithError(OubliException) { _status ->
    UniffiLib.INSTANCE.uniffi_oubli_bridge_fn_constructor_oubliwallet_new(
        FfiConverterTypePlatformStorageCallback.lower(`storage`),FfiConverterOptionalString.lower(`rpcUrl`),FfiConverterOptionalString.lower(`paymasterApiKey`),_status)
}
    )

    protected val pointer: Pointer?
    protected val cleanable: UniffiCleaner.Cleanable

    private val wasDestroyed = AtomicBoolean(false)
    private val callCounter = AtomicLong(1)

    override fun destroy() {
        // Only allow a single call to this method.
        // TODO: maybe we should log a warning if called more than once?
        if (this.wasDestroyed.compareAndSet(false, true)) {
            // This decrement always matches the initial count of 1 given at creation time.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable.clean()
            }
        }
    }

    @Synchronized
    override fun close() {
        this.destroy()
    }

    internal inline fun <R> callWithPointer(block: (ptr: Pointer) -> R): R {
        // Check and increment the call counter, to keep the object alive.
        // This needs a compare-and-set retry loop in case of concurrent updates.
        do {
            val c = this.callCounter.get()
            if (c == 0L) {
                throw IllegalStateException("${this.javaClass.simpleName} object has already been destroyed")
            }
            if (c == Long.MAX_VALUE) {
                throw IllegalStateException("${this.javaClass.simpleName} call counter would overflow")
            }
        } while (! this.callCounter.compareAndSet(c, c + 1L))
        // Now we can safely do the method call without the pointer being freed concurrently.
        try {
            return block(this.uniffiClonePointer())
        } finally {
            // This decrement always matches the increment we performed above.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable.clean()
            }
        }
    }

    // Use a static inner class instead of a closure so as not to accidentally
    // capture `this` as part of the cleanable's action.
    private class UniffiCleanAction(private val pointer: Pointer?) : Runnable {
        override fun run() {
            pointer?.let { ptr ->
                uniffiRustCall { status ->
                    UniffiLib.INSTANCE.uniffi_oubli_bridge_fn_free_oubliwallet(ptr, status)
                }
            }
        }
    }

    fun uniffiClonePointer(): Pointer {
        return uniffiRustCall() { status ->
            UniffiLib.INSTANCE.uniffi_oubli_bridge_fn_clone_oubliwallet(pointer!!, status)
        }
    }

