public object FfiConverterTypeOubliWallet: FfiConverter<OubliWallet, Pointer> {

    override fun lower(value: OubliWallet): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): OubliWallet {
        return OubliWallet(value)
    }

    override fun read(buf: ByteBuffer): OubliWallet {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: OubliWallet) = 8UL

    override fun write(value: OubliWallet, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



