sealed class OubliException(message: String): kotlin.Exception(message) {
        
        class Auth(message: String) : OubliException(message)
        
        class Store(message: String) : OubliException(message)
        
        class Backup(message: String) : OubliException(message)
        
        class Kms(message: String) : OubliException(message)
        
        class Rpc(message: String) : OubliException(message)
        
        class Paymaster(message: String) : OubliException(message)
        
        class InvalidState(message: String) : OubliException(message)
        
        class NoActiveAccount(message: String) : OubliException(message)
        
        class Denomination(message: String) : OubliException(message)
        
        class InsufficientBalance(message: String) : OubliException(message)
        
        class Network(message: String) : OubliException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<OubliException> {
        override fun lift(error_buf: RustBuffer.ByValue): OubliException = FfiConverterTypeOubliError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeOubliError : FfiConverterRustBuffer<OubliException> {
    override fun read(buf: ByteBuffer): OubliException {
        
            return when(buf.getInt()) {
            1 -> OubliException.Auth(FfiConverterString.read(buf))
            2 -> OubliException.Store(FfiConverterString.read(buf))
            3 -> OubliException.Backup(FfiConverterString.read(buf))
            4 -> OubliException.Kms(FfiConverterString.read(buf))
            5 -> OubliException.Rpc(FfiConverterString.read(buf))
            6 -> OubliException.Paymaster(FfiConverterString.read(buf))
            7 -> OubliException.InvalidState(FfiConverterString.read(buf))
            8 -> OubliException.NoActiveAccount(FfiConverterString.read(buf))
            9 -> OubliException.Denomination(FfiConverterString.read(buf))
            10 -> OubliException.InsufficientBalance(FfiConverterString.read(buf))
            11 -> OubliException.Network(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: OubliException): ULong {
        return 4UL
    }

    override fun write(value: OubliException, buf: ByteBuffer) {
        when(value) {
            is OubliException.Auth -> {
                buf.putInt(1)
                Unit
            }
            is OubliException.Store -> {
                buf.putInt(2)
                Unit
            }
            is OubliException.Backup -> {
                buf.putInt(3)
                Unit
            }
            is OubliException.Kms -> {
                buf.putInt(4)
                Unit
            }
            is OubliException.Rpc -> {
                buf.putInt(5)
                Unit
            }
            is OubliException.Paymaster -> {
                buf.putInt(6)
                Unit
            }
            is OubliException.InvalidState -> {
                buf.putInt(7)
                Unit
            }
            is OubliException.NoActiveAccount -> {
                buf.putInt(8)
                Unit
            }
            is OubliException.Denomination -> {
                buf.putInt(9)
                Unit
            }
            is OubliException.InsufficientBalance -> {
                buf.putInt(10)
                Unit
            }
            is OubliException.Network -> {
                buf.putInt(11)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




